import { syntaxTree } from '@codemirror/language';
import { RangeSetBuilder } from '@codemirror/state';
import { ViewPlugin } from '@codemirror/view';
import type {
  Decoration,
  DecorationSet,
  EditorView,
  ViewUpdate,
} from '@codemirror/view';

import { keyMark } from './decoration-marks.js';

/**
 * Create a range set with decorations for all the filter keys.
 * @internal
 */
export function createFilterKeyDecorations(view: EditorView) {
  const builder = new RangeSetBuilder<Decoration>();

  for (const { from, to } of view.visibleRanges) {
    syntaxTree(view.state).iterate({
      from,
      to,
      enter: (node) => {
        if (node.name === 'FilterKey') {
          const { from: keyFrom, to: keyTo } = node;
          builder.add(keyFrom, keyTo, keyMark);

          return false;
        }
      },
    });
  }

  return builder.finish();
}

/**
 * View plugin to wrap all filter keys in spans.
 * @internal
 */
export const FilterKeyDecorationPlugin = ViewPlugin.fromClass(
  class {
    decorations: DecorationSet;

    constructor(view: EditorView) {
      this.decorations = createFilterKeyDecorations(view);
    }

    update(update: ViewUpdate) {
      if (update.docChanged) {
        this.decorations = createFilterKeyDecorations(update.view);
      }
    }
  },
  {
    decorations: (view) => view.decorations,
  },
);
